import React from 'react';
import { Card, Row, Col, Tag, Button, Typography, Space, Empty } from 'antd';
import { useParams, useLocation, useNavigate } from 'react-router-dom';
import {
  UserOutlined,
  FileOutlined,
  BankOutlined,
  FileDoneOutlined,
  EditOutlined,
  ArrowLeftOutlined,
} from '@ant-design/icons';
import axiosInstance from '../../axiosConfig';
import DOMPurify from 'dompurify';

const { Title, Text } = Typography;

// Extracted InfoCard component to avoid creating components during render
const InfoCard = ({ onBack, title, icon, children }) => (
  <Card
    button={
      <ArrowLeftOutlined
        onClick={onBack}
        style={{
          marginBottom: '20px',
          fontSize: '18px',
          color: 'blue',
          border: '1px solid grey',
          borderRadius: '50%',
          padding: '10px',
        }}
      />
    }
    title={
      <Space>
        {icon}
        <Text strong>{title}</Text>
      </Space>
    }
    style={{ marginBottom: '20px', borderRadius: '15px', boxShadow: '0 4px 6px rgba(0,0,0,0.1)' }}
  >
    {children}
  </Card>
);

// Extracted InfoItem component
const InfoItem = ({ label, value, isHTML = false }) => (
  <Row style={{ marginBottom: '12px' }}>
    <Col span={10}>
      <Text type="secondary">{label}</Text>
    </Col>
    <Col span={14}>
      <Text strong>
        {isHTML && typeof value === 'string'
          ? DOMPurify.sanitize(value, {
              ALLOWED_TAGS: ['p', 'br', 'b', 'i', 'strong'],
              ALLOWED_ATTR: [],
            })
          : DOMPurify.sanitize(String(value || ''), { ALLOWED_TAGS: [], ALLOWED_ATTR: [] })}
      </Text>
    </Col>
  </Row>
);

function CaseDetails() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { state } = useLocation();
  const [caseDetails, setCaseDetails] = React.useState(state?.case1 || null);

  React.useEffect(() => {
    if (caseDetails) {
      return;
    }
    const fetchCase = async () => {
      try {
        const response = await axiosInstance.get(`/case/${id}/`);
        setCaseDetails(response.data);
      } catch (error) {
        console.error('Error fetching case:', error);
      }
    };
    fetchCase();
  }, [caseDetails, id]);

  const handleBack = () => {
    navigate(-1);
  };

  const handleEdit = () => {
    navigate('/case-form/', { state: { case: caseDetails, isEditing: true } });
  };

  const handleBackClick = () => {
    navigate('/case-list');
  };

  return (
    <div style={{ padding: '20px', minHeight: '100vh', marginTop: '40px' }}>
      {!caseDetails ? (
        <Card>Case not found.</Card>
      ) : (
        <Card
          title={
            <Space size="middle">
              <Button
                icon={<ArrowLeftOutlined />}
                onClick={handleBack}
                type="text"
                style={{ fontSize: '18px' }}
              />
              <Title level={2} style={{ margin: 0 }}>
                {DOMPurify.sanitize(caseDetails.title || '', {
                  ALLOWED_TAGS: [],
                  ALLOWED_ATTR: [],
                })}
              </Title>
            </Space>
          }
          extra={
            <Button type="primary" icon={<EditOutlined />} onClick={handleEdit}>
              Edit Case
            </Button>
          }
          style={{ borderRadius: '20px', overflow: 'hidden' }}
          bodyStyle={{ padding: '30px' }}
        >
          <Row gutter={[16, 16]}>
            <Col xs={24} sm={24} md={12} lg={12} xl={12}>
              <InfoCard onBack={handleBackClick} title="Case Details" icon={<FileOutlined />}>
                <InfoItem label="Case Number" value={caseDetails.case_number} />
                <InfoItem
                  label="Status"
                  value={
                    <Tag
                      color={
                        caseDetails.status === 'open'
                          ? '#1890ff'
                          : caseDetails.status === 'pending'
                            ? '#faad14'
                            : caseDetails.status === 'closed'
                              ? '#52c41a'
                              : 'default'
                      }
                      style={{ borderRadius: '20px', padding: '0 10px' }}
                    >
                      {caseDetails.status.toUpperCase()}
                    </Tag>
                  }
                />
                <InfoItem label="Start Date" value={caseDetails.start_date} />
                <InfoItem label="End Date" value={caseDetails.end_date} />
              </InfoCard>

              <InfoCard onBack={handleBackClick} title="Client" icon={<UserOutlined />}>
                <InfoItem label="Name" value={caseDetails.name} />
              </InfoCard>

              <InfoCard onBack={handleBackClick} title="Advocate" icon={<UserOutlined />}>
                <InfoItem label="Name" value={caseDetails.advocate?.username || 'Unassigned'} />
              </InfoCard>
            </Col>

            <Col xs={24} sm={24} md={12} lg={12} xl={12}>
              <InfoCard onBack={handleBackClick} title="Court" icon={<BankOutlined />}>
                <InfoItem label="Name" value={caseDetails.court_name} />
              </InfoCard>

              <InfoCard onBack={handleBackClick} title="Organization" icon={<BankOutlined />}>
                <InfoItem label="Name" value={caseDetails.organization?.name} />
              </InfoCard>

              <InfoCard onBack={handleBackClick} title="Case Information" icon={<FileOutlined />}>
                <Text>
                  {DOMPurify.sanitize(caseDetails.description || '', {
                    ALLOWED_TAGS: ['p', 'br', 'b', 'i', 'strong', 'em'],
                    ALLOWED_ATTR: [],
                  })}
                </Text>
              </InfoCard>

              <InfoCard
                onBack={handleBackClick}
                title="Associated Documents"
                icon={<FileDoneOutlined />}
              >
                {caseDetails.documents && caseDetails.documents.length > 0 ? (
                  <Space direction="vertical" style={{ width: '100%' }}>
                    {caseDetails.documents.map((doc, index) => (
                      <Button
                        key={index}
                        icon={<FileOutlined />}
                        style={{ borderRadius: '20px', width: '100%', textAlign: 'left' }}
                      >
                        {DOMPurify.sanitize(doc.name || '', { ALLOWED_TAGS: [], ALLOWED_ATTR: [] })}
                      </Button>
                    ))}
                  </Space>
                ) : (
                  <Empty
                    image={Empty.PRESENTED_IMAGE_SIMPLE}
                    description="No associated documents available"
                  />
                )}
              </InfoCard>

              <InfoCard
                onBack={handleBackClick}
                title="Associated Documents"
                icon={<FileDoneOutlined />}
              >
                {caseDetails.documents && caseDetails.documents.length > 0 ? (
                  <Space direction="vertical" style={{ width: '100%' }}>
                    {caseDetails.documents.map((doc, index) => (
                      <Button
                        key={index}
                        icon={<FileOutlined />}
                        style={{ borderRadius: '20px', width: '100%', textAlign: 'left' }}
                      >
                        {doc.name}
                      </Button>
                    ))}
                  </Space>
                ) : (
                  <Empty
                    image={Empty.PRESENTED_IMAGE_SIMPLE}
                    description="No associated documents available"
                  />
                )}
              </InfoCard>
            </Col>
          </Row>
        </Card>
      )}
    </div>
  );
}

export default CaseDetails;
